INSERT INTO `posts` (`post_ID`, `name`, `overview`, `information`, `banner`, `thumbnail`, `createdBy`, `updatedBy`, `created_at`, `updated_at`) VALUES
(2, 'Margarita Village', 'Hotel Todo Incluido - Isla de Margarita', 'El Hotel Margarita Village Ubicado en la AV. Bolívar de Porlamar, a solo 40 minutos del Aeropuerto Internacional Santiago Mariño, con un servicio todo incluido, múltiples instalaciones y con una ubicación privilegiada ya que permite el fácil acceso a playas y a áreas comerciales de la Isla de Margarita.\n\nEs un hotel con habitaciones tipo cabañas con un estilo tropical, ofrece tranquilidad, confort, diversas actividades de animación y recreación, excelentes servicios en todas sus áreas, y una gran variedad gastronómica. Sin duda este hotel es ideal para todos los gustos y edades.', NULL, 'http://localhost:8000/storage/uploads/1776035830_Q7X2mZtHb5.jpg', 1, 1, NULL, NULL),
(4, 'Vacaciones de Verano', 'Vacaciones Toso Incluido', 'Disfruta de unas vacaiones inolvidables en la isla de Margarita con un plan todo incluido.\n\nEl Hotel Margarita Village posee un ambiente ameno y tropical, con una excelente atención a los visitantes. Ubicado a 40 minutos del aeropuerto y cerca de los centros comerciales es el lugar ideal para vacacionar.\n\nDisfruta este plan que incluye:\n\nAlojamiento en habitación doble\n\nTodas las comidas (Desayuno, almuerzo, snack, cena)\n\nBebidas nacionales ilimitadas\n\nPiscina\n\nClub de playa\n\nAnimación y recreación\n\n¡Contáctanos y planifica tu viaje soñado!', 'http://localhost:8000/storage/uploads/1775775171_IN4q09baa8.jpg', 'http://localhost:8000/storage/uploads/1775775166_TUCD9OlY9G.jpg', 1, 1, NULL, NULL),
(7, 'Verano en Margarita', 'ee', 'ee', '', '', 1, 1, NULL, NULL),
(8, 'sdf', 'weee', 'eee', '', '', 1, 1, NULL, NULL),
(9, 'ddddd', '33', 'eeee', '', '', 1, 1, NULL, NULL),
(10, 'Conoce Bogotá', 'Boletos Aéreos a Bogotá - Colombia', 'Bogotá te espera para una gran aventura. Conoce lugares increíbles como el Museo del Oro, la Catedral de Sal o la Montaña de Monserrate\n\n𝐑𝐄𝐐𝐔𝐈𝐒𝐈𝐓𝐎𝐒 𝐏𝐀𝐑𝐀 𝐕𝐈𝐀𝐉𝐀𝐑 𝐀 𝐂𝐎𝐋𝐎𝐌𝐁𝐈𝐀\n\nPara ingresar a Colombia desde Venezuela, los ciudadanos venezolanos necesitan los siguientes documentos:\n\nPasaporte vigente o con hasta 10 años de haber perdido su vigencia\n\nCédula de identidad venezolana\n\nPermiso Especial de Permanencia (PEP) o Permiso por Protección Temporal (PPT)\n\nTarjeta de Movilidad Fronteriza (TMF)\n\nActa de nacimiento para menores de edad\n\nSe debe diligenciar el Check-Mig en la página de Migración Colombia\n\n- Incluye 1 maleta de 23 kilos\n- Tarifa para febrero 2026', NULL, 'http://localhost:8000/storage/uploads/1776388080_4gU58bhGlk.jpg', 1, 1, NULL, NULL),
(11, 'Explora Medellín', 'Oferta en Boletos Aéreos para Medellín-Colombia', '𝐌Á𝐒 𝐈𝐍𝐅𝐎𝐑𝐌𝐀𝐂𝐈Ó𝐍: Medellín, el corazón de Antioquia. \n\nDesde la calidez de su gente hasta su transformación urbana de clase mundial, cada rincón de la ciudad ofrece una mezcla perfecta entre modernidad y tradición cafetera. \n\n¿Por qué elegir este Destino? \n\nMedellín no es solo un destino, es una experiencia sensorial. Al reservar esta tarifa, aseguras tu lugar en la temporada de febrero, ideal para disfrutar del clima templado sin las multitudes de fin de año. \n\n𝐃𝐞𝐭𝐚𝐥𝐥𝐞𝐬 𝐝𝐞 𝐭𝐮 𝐫𝐞𝐬𝐞𝐫𝐯𝐚: \n🔹Vuelo con escala en Panamá\n🔹Tarifa para febrero 2026 \n🔹 Incluye 1 maleta de 23 kilos', NULL, 'http://localhost:8000/storage/uploads/1776431319_T6WJT23TUZ.jpg', 1, 1, NULL, NULL),
(16, 'Top 10 Mejores Playas De Isla De Margarita', 'La Isla de Margarita, cuenta con playas hermosas de arenas blanquecinas y aguas cristalinas con temperaturas que oscilan entre los 20° y 30°', '𝐋𝐚 𝐈𝐬𝐥𝐚 𝐝𝐞 𝐌𝐚𝐫𝐠𝐚𝐫𝐢𝐭𝐚 perteneciente al Estado Nueva Esparta, Venezuela, cuenta con playas hermosas de arenas blanquecinas y aguas cristalinas con temperaturas que oscilan entre los 20° y 30°, lo que las hace ideales para el disfrute de todos, donde se pueden realizar actividades acuáticas y deleitarse con excelente gastronomía, volviendo a Margarita el lugar favorito para el turismo nacional e internacional.\n\n¿Sabías que Margarita tiene aproximadamente 70 playas?\n\nEntre aguas un poco frías en la costa norte de la isla y cálidas al sur, Margarita cuenta con alrededor de 70 playas que ofrecen al turista experiencias únicas, desde donde puedes practicar los mejores deportes acuáticos hasta observar atardeceres de ensueño.  \n\nLas 10 mejores playas de Margarita:\n\n𝟏. 𝐏𝐥𝐚𝐲𝐚 𝐞𝐥 𝐀𝐠𝐮𝐚\n\nSe trata de una de las playas más emblemáticas de la isla, con una extensión de 4km es ideal para pasar un rato agradable en familia, además por ser una zona de gran desarrollo turístico podrás encontrar excelentes restaurantes y comercios a su alrededor. \n\n𝟐. 𝐏𝐥𝐚𝐲𝐚 𝐆𝐮𝐚𝐜𝐮𝐜𝐨\n\nEs una playa extensa con oleaje moderado, se apunta como una gran favorita de los locales. Cuenta con estacionamiento y varios restaurantes típicos que le dan un atractivo adicional. \n\n𝟑. 𝐏𝐥𝐚𝐲𝐚 𝐄𝐥 𝐘𝐚𝐪𝐮𝐞\n\nSe encuentra a cinco minutos del Aeropuerto Internacional Santiago Mariño, en el lado sur de la isla, es de las playas más conocidas, perfecta para familias por su oleaje suave e ideal para los deportes acuáticos como el windsurf y el kitesurf.\n\n𝟒. 𝐏𝐥𝐚𝐲𝐚 𝐏𝐚𝐫𝐠𝐮𝐢𝐭𝐨\n\nSituada al extremo norte de la Isla de Margarita, Parguito, es una de las playas más famosas y buscadas por los turistas, con una ambiente jovial se vuelve el punto ideal para celebrar y disfrutar de un día soleado. \n\n𝟓. 𝐏𝐥𝐚𝐲𝐚 𝐏𝐮𝐧𝐭𝐚 𝐀𝐫𝐞𝐧𝐚𝐬\n\nEs el punto más occidental de la Isla de Margarita, un paraíso de arena fina y aguas cristalinas. A pesar de estar bastante alejada de las principales ciudades ofrece todos los servicios para los visitantes, como toldos y restaurantes. \n\n𝟔. 𝐏𝐥𝐚𝐲𝐚 𝐂𝐚𝐫𝐢𝐛𝐞\n\nEs una pequeña bahía ubicada a minutos de la ciudad de Juan Griego, considerada una de las playas más bonitas de la isla, ofrece encantadores paisajes y restaurantes con una variada oferta gastronómica. \n\n𝟕. 𝐏𝐥𝐚𝐲𝐚 𝐂𝐚𝐫𝐞 𝐂𝐚𝐫𝐞\n\nEs una playa hermosa que se ha convertido en atractivo turístico para los amantes de las actividades al aire libre, ya que se encuentra retirada y sus únicas vías de acceso son por bote o senderismo, un recorrido que vale la pena para llegar a este increíble lugar.\n\n𝟖. 𝐏𝐥𝐚𝐲𝐚 𝐋𝐚 𝐑𝐞𝐬𝐭𝐢𝐧𝐠𝐚\n\nEs la playa más extensa de la isla con 27km, su arena blanca en la que puede observar conchas es perfecta para tomar el sol. Se encuentra dentro del Parque Nacional Laguna de La Restinga, para llegar a ella solo hay que tomar un bote en el muelle del parque. \n\n𝟗. 𝐏𝐥𝐚𝐲𝐚 𝐋𝐚 𝐆𝐚𝐥𝐞𝐫𝐚\n\nCalificada con una de las aguas más pacíficas de la Isla, es ideal para familias con niños y bañistas que temen a un oleaje más fuerte. \n\n𝟏𝟎. 𝐏𝐥𝐚𝐲𝐚 𝐌𝐚𝐧𝐳𝐚𝐧𝐢𝐥𝐥𝐨\n\nEs de las favoritas de los locales, se trata de una bonita bahía llena de pequeños y coloridos peñeros, es una playa de pescadores donde se puede observar por las mañanas a las personas tirando de redes que traen la faena.\n\n\n¿Quieres conocer estas y más playas en Margarita? ¡Recorre la Isla con nosotros!', 'http://localhost:8000/storage/uploads/1775794725_4gSvn43xiv.jpg', 'http://localhost:8000/storage/uploads/1776386465_6Bmk4pZwwH.jpg', 1, 1, NULL, NULL),
(17, 'Sunsol Isla Caribe', 'Sunsol Isla Caribe - Isla de Margarita', 'Sunsol Isla Caribe, un paraíso todo incluido en Isla de Margarita.\n\nSi buscas unas vacaciones sin preocupaciones, este hotel es para ti. Ideal tanto para familias como para parejas, el SUNSOL Isla Caribe te ofrece todo lo que necesitas sin tener que salir del hotel.\n\n✅ Régimen todo incluido: Comidas y bebidas sin límites durante toda tu estancia.\n✅ Tres piscinas con cascada.\n✅ Dos clubes de playa .\n✅ Actividades para niños y adultos: Animación, discoteca y cenas temáticas incluidas.\n✅ Wi-Fi gratuito en el lobby \n✅ Amplias habitaciones\n\n¿Tienes un evento en mente? También cuentan con espacios para reuniones sociales o corporativas, con un equipo experto en planificación para que todo salga perfecto.', 'http://localhost:8000/storage/uploads/1776038202_FC50a4NPkV.jpg', 'http://localhost:8000/storage/uploads/1776038218_ZxSJAM56kE.jpg', 1, 1, NULL, NULL),
(18, 'Sunsol Ecoland', 'Sunsol Ecoland - Isla de Margarita', 'Hotel 4 estrellas todo incluido en Margarita\n\n¿Imaginas unas vacaciones donde puedas pasar de la laguna al mar, de la duna a la montaña sin cambiar de hotel? Este complejo de 4 estrellas con todo incluido lo hace posible. Ubicado frente a una espectacular bahía de aguas azules y arena blanca de un kilómetro de extensión, es el destino perfecto para familias, parejas y amantes de la naturaleza y la aventura.\n\nExperiencias únicas por ecosistema:\n\n✅ Laguna y manglares: Pasea en kayak o bote a pedal (costo adicional).\n✅Mar: Disfruta del boulevard con ciclovía frente al mar.\n✅ Duna de arena: Zona recreativa de duna para los más pequeños y jóvenes.\n✅Montaña: Senderismo hasta el faro con vistas increíbles.\n\n🏨 Instalaciones y servicios destacados:\n\n✅ 4 piscinas familiares + 1 piscina infantil.\n✅ Golfito de 18 hoyos (costo adicional).\n✅3 restaurantes buffet con cenas temáticas + 1 restaurante a la carta (costo adicional) + 2 snack bares.\n✅ 7 bares, discoteca, sala de cine y anfiteatro.\n✅ Parque infantil y club de niños.\n✅ Cancha de usos múltiples y actividades deportivas.\n✅Salón de conferencias.\n✅Servicio de taxi para moverte con comodidad.', 'http://localhost:8000/storage/uploads/1776039740_lokhP0zU0n.jpg', 'http://localhost:8000/storage/uploads/1776039774_d4Db5leddS.jpg', 1, 1, NULL, NULL),
(19, 'Sunsol Punta Blanca', 'Sunsol Punta Blanca - Isla de Coche', '', 'http://localhost:8000/storage/uploads/1776041981_NX1uyvib5t.webp', 'http://localhost:8000/storage/uploads/1776041991_XlfR0hMCoo.jpg', 1, 1, NULL, NULL),
(20, 'Costa Caribe', 'Hotel Todo Incluido - Isla de Margarita', 'Costa Caribe Hotel ubicado frente al mar Caribe en Playa Arenas (Playa de arena) a unos 3 km del pueblo de Juan Griego y a 25 km del aeropuerto. Habitaciones: compuesto por edificios de 2 y 3 niveles con más de 400 cómodas habitaciones decoradas en un estilo rústico caribeño auténtico. Diseñado en tres tipos: 81 Junior Suites, con dormitorio separado y 1 cama doble, sala de estar con sofá cama, balcón o terraza. 243 habitaciones estándar, con dormitorio y 2 camas individuales, balcón o terraza y 81 habitaciones económicas, que consta de 1 habitación doble, todas con aire acondicionado, TV a color con ventilador de techo con control remoto, mini nevera, caja fuerte, secador de pelo, teléfono directo y habitación Servicio. Servicios: Restaurante Las Brisas con buffet. Servicio, snack bar y restaurante La Boquita. Restaurante Don Alfredo a la carta, lobby bar La Tortuga, pool bar y discoteca La Boquita Cave. Servicios: playa, piscina, parque infantil, tiendas, deportes acuáticos, 2 canchas de tenis, estacionamiento, lavandería, gimnasio, discoteca, agencia de viajes, alquiler de autos.', 'http://localhost:8000/storage/uploads/1776043907_jE1yJ6lXK1.webp', 'http://localhost:8000/storage/uploads/1776043916_BmVKrhPKmm.jpg', 1, 1, NULL, NULL),
(21, 'Canaima', 'Canaima, El Corazón Verde de Venezuela Que Te Robará el Aliento', '¿Buscas un destino que combine aventura, naturaleza exuberante y una cultura ancestral fascinante? ¡Entonces prepárate para enamorarte de Canaima! Este Parque Nacional, ubicado en el estado Bolívar, Venezuela, es mucho más que un simple lugar; es una experiencia que te transformará. Con sus tepuyes imponentes, sus saltos de agua de ensueño y su selva virgen, Canaima te invita a desconectar del mundo y reconectar contigo mismo. \n\n¿Por Qué Canaima Debería Estar en Tu Lista de Viajes?  Imagina despertar con el sonido de cascadas cayendo a lo lejos, el aroma de la tierra húmeda y la brisa fresca acariciando tu rostro. Esa es solo una probadita de lo que te espera en Canaima. Este paraíso natural es hogar de una biodiversidad increíble y paisajes que parecen sacados de un cuento de hadas.  El Salto Ángel: La Majestad Inigualable: No se puede hablar de Canaima sin mencionar la joya de la corona: el Salto Ángel. Con sus 979 metros de altura, es la cascada más alta del mundo, ¡una maravilla natural que te dejará sin palabras! Verla caer desde el Auyantepuy es una experiencia que se queda grabada para siempre.', 'http://localhost:8000/storage/uploads/1776045630_Zapec6lTx5.jpg', 'http://localhost:8000/storage/uploads/1776045714_8q4M5XpMuR.jpg', 1, 1, '2026-04-01 14:16:54', NULL),
(22, 'Hoteles más Exclusivos de Margarita', 'La Isla de Margarita goza de gran popularidad para el turismo nacional e internacional, sus hermosas playas de aguas cristalinas, lugares históricos y la calidez de su gente la hacen resaltar en el Caribe venezolano', 'La Isla de Margarita goza de gran popularidad para el turismo nacional e internacional, sus hermosas playas de aguas cristalinas, lugares históricos y la calidez de su gente la hacen resaltar en el Caribe venezolano, por ser un  destino popular cuenta con una amplia y variada estructura hotelera de primer nivel.\n\nEntre los hoteles más exclusivos de la Isla de Margarita se encuentran: \n\n𝐈𝐬𝐚𝐛𝐞𝐥 𝐥𝐚 𝐂𝐚𝐭𝐨́𝐥𝐢𝐜𝐚 𝐇𝐨𝐭𝐞𝐥 𝐁𝐨𝐮𝐭𝐢𝐪𝐮𝐞 \n\nEs un pequeño hotel de 14 habitaciones, donde se mezcla la riqueza de la historia con el lujo y la exclusividad. Se encuentra ubicado en el casco histórico de Pampatar, a pocos pasos de la bahía. Ofrece a sus huéspedes cercanía a la playa, sitios turísticos y lugares de compra.\n\nSus habitaciones temáticas están inspiradas en personajes que junto a Isabel La Católica tejieron la historia de su época, como Juana La Loca, María de Aragón o Enrique IV con una visión reinterpretada y moderna. El hotel cuenta con terraza, piscina y un restaurante de exquisita gastronomía.\n\n𝗔𝗿𝗶𝗮 𝗕𝘆 𝗟𝗗 𝗛𝗼𝘁𝗲𝗹 𝗕𝗼𝘂𝘁𝗶𝗾𝘂𝗲\n\nSe trata de un hotel de solo 13 habitaciones, con una modalidad \"Solo adultos\" donde el diseño contemporáneo y el buen gusto se fusionan en un espacio exclusivo, volviéndolo un lugar de ensueño para unas vacaciones inolvidables. \n\nEn Aria podrás vivir experiencias personalizadas, sus habitaciones se convierten en una parte fundamental del viaje, gracias a su majestuosa vista sobre el Mar Caribe. Un lugar paradisíaco ubicado en La Caranta, Pampatar.\n\nSus instalaciones son sinónimo de lujo y confort, cuenta con piscina panorámica con borde infinito, acceso directo a la playa con toldos, sillas y cava de hidratación, área para masajes, relajación y descanso, WiFi, estacionamiento y acceso al restaurante Guayoyo Gastro Bar. \n\n𝗦𝘂𝗻𝘀𝗼𝗹 𝗨𝗻𝗶𝗸 𝗟𝘂𝘅𝘂𝗿𝘆\n\nEs un hotel de ciudad de categoría 5 estrellas, situado en el corazón de Pampatar, en la Urbanización Costa Azul, un excelente parque comercial rodeado de tiendas y supermercados.  Es el hotel ideal para quienes buscan lujo y confort a pocos pasos de los mejores lugares de la Isla. \n\nEn Sunsol Unik, se puede disfrutar del descanso y la relajación en instalaciones de primer nivel, el hotel cuenta con piscina al aire libre, jacuzzi, terraza panorámica, lounch bar, looby bar, sala de juegos, centro de fitness, restaurante, amplias y cómodas habitaciones y acceso a club de playa. \n\nAdemás, posee los espacios ideales para el desarrollo de congresos, eventos corporativos, conciertos, obras de teatro, exposiciones y eventos sociales.\n\n𝗪𝘆𝗻𝗱𝗵𝗮𝗺 𝗖𝗼𝗻𝗰𝗼𝗿𝗱𝗲 𝗥𝗲𝘀𝗼𝗿𝘁 𝗠𝗮𝗿𝗴𝗮𝗿𝗶𝘁𝗮\n\nEs un imponente hotel de categoría 5 estrellas, ubicado en la tranquila zona de Playa Concorde, en la ciudad de Porlamar, con sus 24 pisos se alza como un ícono del turismo de lujo acompañado de una magnifica vista al mar. \n\nEste emblemático hotel cuenta con habitaciones totalmente equipadas con un servicio para club de playa, jardines, parque infantil, una espectacular piscina con un diseño único, salón de juegos, jacuzzis, terrazas y áreas para eventos al aire libre, servicio médico, canchas de tenis y gimnasio. \n\n𝗛𝟮𝗼𝘁𝗲𝗹 𝗕𝗼𝘂𝘁𝗶𝗾𝘂𝗲 𝗕𝘆 𝗟𝗗\n\nUn hermoso y conceptual hotel de lujo que combina el arte, la decoración y una hermosa arquitectura en un sólo lugar, ubicado en Playa El Agua, el H2otel Boutique se consolida como una alternativa de muy alto nivel en dónde la armonía, la calidez y el buen gusto son piezas fundamentales de la experiencia. \n\nEste hotel es el lugar predilecto de los amantes de la buena cocina y del trato exclusivo. Cuenta con acogedoras habitaciones, jacuzzi, piscina, servicio de toallas, toldos, sillas y tumbonas, sauna, área de masajes y Spa, sala de ejercicios, club de niños y tienda de souvenirs. \n\nEstos increíbles hoteles son la mayor referencia de exclusividad en la Isla de Margarita ¿Te gustaría hospedarte en alguno? Comunícate con nosotros.', 'http://localhost:8000/storage/uploads/1776385739_ptCGrtt41e.webp', 'http://localhost:8000/storage/uploads/1776385779_Gya7vaVXiR.jpg', 1, 1, NULL, NULL),
(23, 'Isla de Margarita', 'Te invitamos a conocer Isla de Margarita, donde podrás disfrutar de hermosas playas, variedad de hoteles todo incluido, paisajes hermosos, inigualables atardeceres y diversión para la familia.', 'La Isla de Margarita es el destino ideal para vacacionar, está ubicada en el Mar Caribe al noreste de Venezuela y junto a la Isla de Coche y la Isla de Cubagua pertenecen al estado Nueva Esparta. Consiste en 2 penínsulas conectadas por la Arena y los Manglares del Parque Nacional Laguna de La Restinga.\n\nSi viajas desde Caracas, son 35 minutos de vuelo o un par de horas en ferry desde Puerto La Cruz, La Guaira o Cumaná.\n\nLa Isla de Margarita es considerada como ❞𝐋𝐚 𝐏𝐞𝐫𝐥𝐚 𝐝𝐞𝐥 𝐂𝐚𝐫𝐢𝐛𝐞❞, es el principal destino turístico de Venezuela gracias a su variedad de hoteles, centros comerciales, vida nocturna, restaurantes a las orillas del mar, la belleza de sus playas y su gente, que se caracterizan por ser gentiles y muy serviciales con los turistas.\n\n¿Qué esperas para visitar la Isla de Margarita? Contáctanos y solicita más información.', '', 'http://localhost:8000/storage/uploads/1776386243_ptw70UBWCl.jpg', 1, 1, NULL, NULL),
(24, 'Vuela a Barbados', 'Boletos Aéreos a Barbados', 'Barbados es mucho más que un destino de sol y playa; es una mezcla perfecta de elegancia británica y alma caribeña. Desde la histórica Bridgetown (Patrimonio de la Humanidad) hasta las imponentes olas de la costa este en Bathsheba, esta isla ofrece una experiencia vibrante para cada tipo de viajero.', NULL, 'http://localhost:8000/storage/uploads/1776434866_Of1blgKOtR.jpg', 1, 1, NULL, NULL),
(25, 'Escápate a Cancún', 'Boletos Aéreos a Cancún - México', '¿Buscas el destino perfecto para empezar el año? Vive la magia de Cancún, el lugar donde las aguas cristalinas y la diversión sin fin se unen para regalarte una experiencia inolvidable.\n\nLO QUE INCLUYE TU VIAJE:\n✅ Equipaje: 1 maleta de 23 kg incluida (¡Viaja sin preocupaciones!).\n📅 Temporada: Tarifa exclusiva para Enero 2026.', '', 'http://localhost:8000/storage/uploads/1776439199_OgEKtwBvWm.jpg', 1, 1, NULL, NULL);

